export const STREAM_MOBILE_TRANSLATIONS = { ru, en, uz, zh, kk, ky, tg, tk, az, tr, ar, fa, hi, ur, ko, ja, de, fr, es, it, pt, id, ms, th, vi } as const;
export type StreamSupportedLanguage = keyof typeof STREAM_MOBILE_TRANSLATIONS;


function normalizeLanguage(language?: string | null): StreamSupportedLanguage {
  const value = String(language || "en").toLowerCase().replace("_", "-");
  const short = value.split("-")[0] as StreamSupportedLanguage;
  if (short in STREAM_MOBILE_TRANSLATIONS) return short;
  return "en";
}

export function createStreamMobileTranslator(language?: string | null) {
  const dict = STREAM_MOBILE_TRANSLATIONS[normalizeLanguage(language)];
  return (key: StreamLabelKey): string => dict[key] ?? en[key] ?? ru[key] ?? key;
}
